def test_encaps_internal_768():
    ek = bytes.fromhex("")
    m = bytes.fromhex("3dc27ca0a6594b0e56320457c45a0f76bb8a213ea4a76d442186a0aefadbcdb9")

    expected_K = bytes.fromhex("4b4eba37eff0315dc6009dcffb4dfbbb680f8f2ebde8715fa3d6daf70256a2d9")
    expected_c = bytes.fromhex("")

    K, c = _encaps_internal(ek, m)

    assert K == expected_K
    assert c == expected_c

